<template>
  <div class="wrapper">
    <img src="http://www.dell-lee.com/imgs/vue3/user.png" />
    <div class="wrapper_input">
      <input class="wrapper_input_content" placeholder="请输入用户名" v-model="username" />
    </div>
    <div class="wrapper_input">
      <input class="wrapper_input_content" type="password" placeholder="请输入密码" v-model="password" autocomplete="new-password" />
    </div>
    <div class="wrapper_input">
      <input class="wrapper_input_content" type="password" placeholder="请确认密码" v-model="ensurement" autocomplete="new-password" />
    </div>
    <div class="wrapper_login-button" @click="handleRegister">注册</div>
    <div class="wrapper_login-link" @click="handleLoginClick">已有账号去登陆</div>
  </div>
  <Toast v-if="show" :message="toastMessage" />
</template>

<script>
import { reactive, toRefs } from "vue"
import { useRouter } from "vue-router"
import { post } from '../../utils/request'
import Toast, { useToastEffect } from '../../components/Toast.vue'

const useRegisterEffect = (showToast) => {  // 注册相关逻辑
  const router = useRouter()
  const data = reactive({
    username: '',
    password: '',
    ensurement: ''
  })
  const handleRegister = async () => {
    try {
      const result = await post('/api/user/register', {
        username: data.username,
        password: data.password
      })
      if (result?.errno === 0) {
        router.push({ name: 'Login' })
      } else {
        showToast('注册失败')
      }
    } catch (e) {
      showToast('请求失败')
    }
  }
  const { username, password, ensurement } = toRefs(data)
  return { username, password, ensurement, handleRegister }
}

const useLoginEffect = () => {
  const router = useRouter()
  const handleLoginClick = () => {
    router.push({ path: '/login', query: { type: 1 } })
  }
  return { handleLoginClick }
}

export default {
  name: 'Register',
  components: {
    Toast
  },
  setup() {
    const router = useRouter()
    const { show, toastMessage, showToast } = useToastEffect()
    const { username, password, ensurement, handleRegister } = useRegisterEffect(showToast)
    const { handleLoginClick } = useLoginEffect()
    
    return { username, password, ensurement, show, toastMessage, handleRegister, handleLoginClick }
  }
}
</script>

<style lang="scss" scoped>
  @import '../../styles/variables.scss';
  .wrapper {
    position: absolute;
    top: 50%;
    left: 0;
    right: 0;
    transform: translateY(-50%);
    img {
      display: block;
      margin: 0 auto .4rem auto;
      width: .66rem;
      height: .66rem;
    }
    &_input {
      height: .48rem;
      padding: 0 .16rem;
      box-sizing: border-box;
      margin: 0 .4rem .16rem .4rem;
      background: #f9f9f9;
      border: 1px solid rgba(0, 0, 0, .1);
      border-radius: .06rem;
      &_content {
        line-height: .48rem;
        border: none;  // 去除边框
        outline: none;  // 选中时去除边框
        width: 100%;
        background: none;
        font-size: .16rem;
        color: $content-notice-fontcolor;
        &::placeholder {
          color: $content-notice-fontcolor;
        }
      }
    }
    &_login-button {
      text-align: center;
      margin: .32rem .4rem .16rem .4rem;
      line-height: .48rem;
      font-size: .16rem;
      background: $btn-bgColor;
      color: $bgColor;
      box-shadow: 0 .04rem .08rem 0 rgba(0, 145, 255, .32);
      border-radius: .04rem;
    }
    &_login-link {
      text-align: center;
      font-size: .14rem;
      color: $content-notice-fontcolor;
    }
  }
</style>